{
  "version": "Notebook/1.0",
  "items": [
    {
      "type": 1,
      "content": {
        "json": "<div style='padding:16px 20px;background:#eff6fc;border-left:3px solid #0078d4;border-radius:6px;margin-bottom:8px'><h2 style='margin:0 0 4px 0;color:#0078d4;font-size:18px'>AIRA — AI Platform Readiness Assessment</h2><p style='margin:0;font-size:13px;color:#605e5c'>Evaluates your Azure environment across six readiness pillars. Select subscription(s) to run the assessment.</p></div>"
      },
      "name": "header"
    },
    {
      "type": 9,
      "content": {
        "version": "KqlParameterItem/1.0",
        "parameters": [
          {
            "id": "subscription",
            "version": "KqlParameterItem/1.0",
            "name": "Subscription",
            "type": 6,
            "isRequired": true,
            "multiSelect": true,
            "quote": "'",
            "delimiter": ",",
            "typeSettings": {
              "additionalResourceOptions": [
                "value::all"
              ],
              "includeAll": true,
              "showDefault": false
            },
            "defaultValue": "value::all"
          },
          {
            "id": "pillar-bars-param",
            "version": "KqlParameterItem/1.0",
            "name": "PillarBarsHtml",
            "type": 1,
            "query": "resources\n| summarize purview=countif(type=='microsoft.purview/accounts'), databricks=countif(type=='microsoft.databricks/workspaces'), adf=countif(type=='microsoft.datafactory/factories'), adls=countif(type=='microsoft.storage/storageaccounts' and tobool(properties.isHnsEnabled)==true), aisearch=countif(type=='microsoft.search/searchservices'), redis=countif(type in ('microsoft.cache/redis','microsoft.cache/redisenterprise')), cosmos=countif(type=='microsoft.documentdb/databaseaccounts'), docint=countif(type=='microsoft.cognitiveservices/accounts' and kind in ('FormRecognizer','DocumentIntelligence')), aoai=countif(type=='microsoft.cognitiveservices/accounts' and kind in ('OpenAI','AIServices')), aml=countif(type=='microsoft.machinelearningservices/workspaces'), foundry=countif(type=~'microsoft.cognitiveservices/accounts/projects'), contentsafety=countif(type=='microsoft.cognitiveservices/accounts' and kind=~'ContentSafety'), keyvault=countif(type=='microsoft.keyvault/vaults'), managed_id=countif(type in ('microsoft.cognitiveservices/accounts','microsoft.machinelearningservices/workspaces','microsoft.search/searchservices') and isnotnull(identity)), apim=countif(type=='microsoft.apimanagement/service'), appinsights=countif(type=='microsoft.insights/components')\n| extend Pillars = pack_array(\n    strcat('Data Management & Governance|1|8|', tostring(iff(purview>0,3,0)+iff(databricks>0,2,0)+iff(adf>0,1,0)+iff(adls>0,2,0))),\n    strcat('Retrieval & Context Enablement|2|5|', tostring(iff(aisearch>0,2,0)+iff(redis>0,1,0)+iff(cosmos>0,1,0)+iff(docint>0,1,0))),\n    strcat('Model Management|3|8|', tostring(iff(aoai>0,3,0)+iff(aml>0,2,0)+iff(foundry>0,3,0))),\n    strcat('Responsible AI|4|3|', tostring(iff(contentsafety>0,3,0))),\n    strcat('Security & Compliance|5|7|', tostring(iff(keyvault>0,2,0)+iff(managed_id>0,3,0)+iff(apim>0,2,0))),\n    strcat('Monitoring & Operations|6|5|', tostring(iff(appinsights>0,3,0)+iff(managed_id>0,2,0))))\n| mv-expand Pillars to typeof(string)\n| extend parts = split(Pillars, '|')\n| extend Pillar=tostring(parts[0]), SortOrder=toint(parts[1]), MaxScore=toint(parts[2]), WeightedScore=toint(parts[3])\n| extend ScorePercent=toint(round(100.0*WeightedScore/MaxScore, 0))\n| order by SortOrder asc\n| extend BarColor=iff(ScorePercent>=75, '#00b294', iff(ScorePercent>=40, '#ff8c00', '#e81123'))\n| extend row=strcat('<div style=\"display:flex;align-items:center;gap:10px;padding:7px 0;border-bottom:1px solid #f3f2f1\"><div style=\"min-width:240px;font-size:13px;color:#0078d4;font-weight:600\">', Pillar, '</div><div style=\"flex:1;height:12px;background:#edebe9;border-radius:2px;overflow:hidden;min-width:120px\"><div style=\"height:100%;width:', tostring(ScorePercent), '%;background:', BarColor, ';border-radius:2px\"></div></div><span style=\"min-width:44px;text-align:right;font-size:13px;font-weight:600;color:#323130\">', tostring(ScorePercent), '%</span></div>')\n| summarize allrows=strcat_array(make_list(row), '')\n| project allrows",
            "isHiddenWhenLocked": true,
            "queryType": 1,
            "resourceType": "microsoft.resourcegraph/resources",
            "crossComponentResources": [
              "{Subscription}"
            ]
          },
          {
            "id": "score-card-param",
            "version": "KqlParameterItem/1.0",
            "name": "ScoreCardHtml",
            "type": 1,
            "query": "resources\n| summarize purview=countif(type=='microsoft.purview/accounts'), databricks=countif(type=='microsoft.databricks/workspaces'), adf=countif(type=='microsoft.datafactory/factories'), adls=countif(type=='microsoft.storage/storageaccounts' and tobool(properties.isHnsEnabled)==true), aisearch=countif(type=='microsoft.search/searchservices'), redis=countif(type in ('microsoft.cache/redis','microsoft.cache/redisenterprise')), cosmos=countif(type=='microsoft.documentdb/databaseaccounts'), docint=countif(type=='microsoft.cognitiveservices/accounts' and kind in ('FormRecognizer','DocumentIntelligence')), aoai=countif(type=='microsoft.cognitiveservices/accounts' and kind in ('OpenAI','AIServices')), aml=countif(type=='microsoft.machinelearningservices/workspaces'), foundry=countif(type=~'microsoft.cognitiveservices/accounts/projects'), contentsafety=countif(type=='microsoft.cognitiveservices/accounts' and kind=~'ContentSafety'), keyvault=countif(type=='microsoft.keyvault/vaults'), managed_id=countif(type in ('microsoft.cognitiveservices/accounts','microsoft.machinelearningservices/workspaces','microsoft.search/searchservices') and isnotnull(identity)), apim=countif(type=='microsoft.apimanagement/service'), appinsights=countif(type=='microsoft.insights/components')\n| extend TotalWeighted = iff(purview>0,3,0)+iff(databricks>0,2,0)+iff(adf>0,1,0)+iff(adls>0,2,0)+iff(aisearch>0,2,0)+iff(redis>0,1,0)+iff(cosmos>0,1,0)+iff(docint>0,1,0)+iff(aoai>0,3,0)+iff(aml>0,2,0)+iff(foundry>0,3,0)+iff(contentsafety>0,3,0)+iff(keyvault>0,2,0)+iff(managed_id>0,3,0)+iff(apim>0,2,0)+iff(appinsights>0,3,0)\n| extend MaxTotal = 36\n| extend S = toint(round(100.0 * TotalWeighted / MaxTotal, 0))\n| extend ScoreColor=iff(S>=80, '#107c10', iff(S>=50, '#d69900', '#d13438'))\n| extend RingPct = S * 2.51327\n| extend html=strcat('<div style=\"display:flex;flex-direction:column;align-items:center;justify-content:center;padding:12px 8px\"><div style=\"font-size:13px;font-weight:600;color:#605e5c;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px\">AI Readiness Score</div><div style=\"position:relative;width:160px;height:160px\"><svg viewBox=\"0 0 100 100\" style=\"transform:rotate(-90deg)\"><circle cx=\"50\" cy=\"50\" r=\"40\" fill=\"none\" stroke=\"#edebe9\" stroke-width=\"8\"/><circle cx=\"50\" cy=\"50\" r=\"40\" fill=\"none\" stroke=\"', ScoreColor, '\" stroke-width=\"8\" stroke-dasharray=\"', tostring(RingPct), ' 251.327\" stroke-linecap=\"round\"/></svg><div style=\"position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);text-align:center\"><div style=\"font-size:38px;font-weight:700;color:', ScoreColor, ';line-height:1\">', tostring(S), '%</div></div></div></div>')\n| project html",
            "isHiddenWhenLocked": true,
            "queryType": 1,
            "resourceType": "microsoft.resourcegraph/resources",
            "crossComponentResources": [
              "{Subscription}"
            ]
          }
        ],
        "style": "pills"
      },
      "name": "parameters"
    },
    {
      "type": 12,
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "title": "Assessment Summary",
        "items": [
