            "type": 1,
            "content": {
              "json": "<div style=\"border:1px solid #edebe9;border-radius:8px;background:#fff;box-shadow:0 2px 8px rgba(0,0,0,0.08);height:100%\">{ScoreCardHtml}</div>"
