            "customWidth": "25",
            "name": "overall-score-tile"
          },
          {
            "type": 1,
            "content": {
              "json": "<div style=\"padding:0 4px\">\r\n\r\n**Readiness by Pillar**\r\n\r\n{PillarBarsHtml}\r\n</div>"
            },
            "customWidth": "75",
            "name": "pillar-grid"
          }
        ]
      },
      "name": "summary-group"
    },
    {
      "type": 12,
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "title": "AI Resource Landscape",
        "expandable": true,
        "expanded": false,
        "items": [
          {
            "type": 1,
            "content": {
              "json": "<div style='margin:8px 0;font-size:12px;color:#605e5c'>Geographic distribution of AI-related resources across selected subscriptions. This section is informational and does not affect the readiness score.</div>"
            },
            "name": "landscape-description"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "resources\n| where type in~ (\n    'microsoft.cognitiveservices/accounts',\n    'microsoft.cognitiveservices/accounts/deployments',\n    'microsoft.cognitiveservices/accounts/projects',\n    'microsoft.machinelearningservices/workspaces',\n    'microsoft.search/searchservices',\n    'microsoft.cache/redis',\n    'microsoft.cache/redisenterprise',\n    'microsoft.documentdb/databaseaccounts',\n    'microsoft.purview/accounts',\n    'microsoft.databricks/workspaces',\n    'microsoft.datafactory/factories',\n    'microsoft.apimanagement/service',\n    'microsoft.insights/components'\n  )\n| summarize resourceCount = count() by location\n| order by resourceCount desc",
              "size": 3,
              "title": "AI Resources by Region",
              "queryType": 1,
              "resourceType": "microsoft.resourcegraph/resources",
              "crossComponentResources": [
                "{Subscription}"
              ],
              "visualization": "map",
              "mapSettings": {
                "locInfo": "AzureLoc",
                "locInfoColumn": "location",
                "sizeSettings": "resourceCount",
                "sizeAggregation": "Sum",
                "legendMetric": "resourceCount",
                "legendAggregation": "Sum",
                "itemColorSettings": {
                  "nodeColorField": "resourceCount",
                  "colorAggregation": "Sum",
                  "type": "heatmap",
                  "heatmapPalette": "greenRed"
                }
              },
              "noDataMessage": "No AI resources found in the selected subscription(s).",
              "noDataMessageStyle": 4
            },
            "name": "landscape-map"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "resources\n| where type in~ (\n    'microsoft.cognitiveservices/accounts',\n    'microsoft.cognitiveservices/accounts/deployments',\n    'microsoft.cognitiveservices/accounts/projects',\n    'microsoft.machinelearningservices/workspaces',\n    'microsoft.search/searchservices',\n    'microsoft.cache/redis',\n    'microsoft.cache/redisenterprise',\n    'microsoft.documentdb/databaseaccounts',\n    'microsoft.purview/accounts',\n    'microsoft.databricks/workspaces',\n    'microsoft.datafactory/factories',\n    'microsoft.apimanagement/service',\n    'microsoft.insights/components'\n  )\n| extend serviceCategory = case(\n    type =~ 'microsoft.cognitiveservices/accounts' and kind in~ ('OpenAI','AIServices'), 'Azure OpenAI / AI Services',\n    type =~ 'microsoft.cognitiveservices/accounts' and kind =~ 'ContentSafety', 'Content Safety',\n    type =~ 'microsoft.cognitiveservices/accounts', 'Cognitive Services',\n    type =~ 'microsoft.cognitiveservices/accounts/deployments', 'Model Deployment',\n    type =~ 'microsoft.cognitiveservices/accounts/projects', 'AI Foundry Project',\n    type =~ 'microsoft.machinelearningservices/workspaces', 'ML Workspace',\n    type =~ 'microsoft.search/searchservices', 'AI Search',\n    type in~ ('microsoft.cache/redis','microsoft.cache/redisenterprise'), 'Redis Cache',\n    type =~ 'microsoft.documentdb/databaseaccounts', 'Cosmos DB',\n    type =~ 'microsoft.purview/accounts', 'Purview',\n    type =~ 'microsoft.databricks/workspaces', 'Databricks',\n    type =~ 'microsoft.datafactory/factories', 'Data Factory',\n    type =~ 'microsoft.apimanagement/service', 'API Management',\n    type =~ 'microsoft.insights/components', 'App Insights',\n    'Other'\n  )\n| summarize resourceCount = count() by location, serviceCategory\n| order by location asc, serviceCategory asc",
              "size": 3,
              "title": "AI Resources by Region & Service",
              "queryType": 1,
              "resourceType": "microsoft.resourcegraph/resources",
              "crossComponentResources": [
                "{Subscription}"
              ],
              "visualization": "table",
              "gridSettings": {
                "formatters": [
                  {
                    "columnMatch": "resourceCount",
                    "formatter": 8,
                    "formatOptions": {
                      "palette": "blue"
                    }
                  }
                ]
              },
              "noDataMessage": "No AI resources found in the selected subscription(s).",
              "noDataMessageStyle": 4
            },
            "name": "landscape-table"
          }
        ]
      },
      "name": "landscape-group"
    },
    {
      "type": 12,
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "title": "Data Management & Governance",
        "expandable": true,
        "expanded": false,
        "items": [
          {
            "type": 1,
            "content": {
              "json": "<div style='margin:16px 0 4px 0;border-bottom:1px solid #edebe9;padding-bottom:4px'><span style='font-size:11px;font-weight:600;color:#0078d4;text-transform:uppercase;letter-spacing:.5px'>DMG-001</span>&nbsp;&nbsp;<span style='font-size:14px;font-weight:600;color:#323130'>Purview Accounts</span><span style='font-size:12px;color:#605e5c;margin-left:8px'>Microsoft Purview &#x2014; Unified data governance platform.</span></div>"
            },
            "name": "dmg001-header"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "resources\n| where type == 'microsoft.purview/accounts'\n| project name, location, subscriptionId, properties",
              "size": 3,
              "title": "Purview Accounts",
              "queryType": 1,
              "resourceType": "microsoft.resourcegraph/resources",
              "crossComponentResources": [
                "{Subscription}"
              ],
              "visualization": "table",
              "gridSettings": {
                "formatters": [
                  {
                    "columnMatch": "name",
                    "formatter": 13,
                    "formatOptions": {
                      "linkTarget": "Resource",
                      "showIcon": true
                    }
                  }
                ]
              },
              "noDataMessage": "No resources found in the selected subscription(s).",
              "noDataMessageStyle": 4
            },
            "name": "dmg001-query"
          },
          {
            "type": 1,
            "content": {
              "json": "<div style='margin:16px 0 4px 0;border-bottom:1px solid #edebe9;padding-bottom:4px'><span style='font-size:11px;font-weight:600;color:#0078d4;text-transform:uppercase;letter-spacing:.5px'>DMG-002</span>&nbsp;&nbsp;<span style='font-size:14px;font-weight:600;color:#323130'>Purview Scan Rulesets</span><span style='font-size:12px;color:#605e5c;margin-left:8px'>Validate scan rulesets are configured for data discovery.</span></div>"
