          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "resources\n| where type == 'microsoft.purview/accounts'\n| where isnotnull(properties.scanRulesets)\n| project name, location, subscriptionId, scanRulesets=properties.scanRulesets",
              "size": 3,
              "title": "Purview Scan Rulesets",
              "queryType": 1,
              "resourceType": "microsoft.resourcegraph/resources",
              "crossComponentResources": [
                "{Subscription}"
              ],
              "visualization": "table",
              "noDataMessage": "No resources found in the selected subscription(s).",
              "noDataMessageStyle": 4
            },
            "name": "dmg002-query"
          },
          {
            "type": 1,
            "content": {
              "json": "<div style='margin:16px 0 4px 0;border-bottom:1px solid #edebe9;padding-bottom:4px'><span style='font-size:11px;font-weight:600;color:#0078d4;text-transform:uppercase;letter-spacing:.5px'>DMG-003</span>&nbsp;&nbsp;<span style='font-size:14px;font-weight:600;color:#323130'>Data Classification Rules</span><span style='font-size:12px;color:#605e5c;margin-left:8px'>Check for cloud connector configurations enabling data classification.</span></div>"
            },
            "name": "dmg003-header"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "resources\n| where type == 'microsoft.purview/accounts'\n| where isnotnull(properties.cloudConnectors)\n| project name, location, subscriptionId, properties",
              "size": 3,
              "title": "Data Classification Rules",
              "queryType": 1,
              "resourceType": "microsoft.resourcegraph/resources",
              "crossComponentResources": [
                "{Subscription}"
              ],
              "visualization": "table",
              "noDataMessage": "No resources found in the selected subscription(s).",
              "noDataMessageStyle": 4
            },
            "name": "dmg003-query"
          },
          {
            "type": 1,
            "content": {
              "json": "<div style='margin:16px 0 4px 0;border-bottom:1px solid #edebe9;padding-bottom:4px'><span style='font-size:11px;font-weight:600;color:#0078d4;text-transform:uppercase;letter-spacing:.5px'>DMG-004</span>&nbsp;&nbsp;<span style='font-size:14px;font-weight:600;color:#323130'>Data Lineage Enablement</span><span style='font-size:12px;color:#605e5c;margin-left:8px'>Verify lineage endpoints are configured for tracking data flow.</span></div>"
            },
            "name": "dmg004-header"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "resources\n| where type == 'microsoft.purview/accounts'\n| extend lineageEndpoint = tostring(properties.endpoints.lineage)\n| where isnotnull(lineageEndpoint)\n| project name, lineageEndpoint, location, subscriptionId",
              "size": 3,
              "title": "Data Lineage Enablement",
              "queryType": 1,
              "resourceType": "microsoft.resourcegraph/resources",
              "crossComponentResources": [
                "{Subscription}"
              ],
              "visualization": "table",
              "noDataMessage": "No resources found in the selected subscription(s).",
              "noDataMessageStyle": 4
            },
            "name": "dmg004-query"
          },
          {
            "type": 1,
            "content": {
              "json": "<div style='margin:16px 0 4px 0;border-bottom:1px solid #edebe9;padding-bottom:4px'><span style='font-size:11px;font-weight:600;color:#0078d4;text-transform:uppercase;letter-spacing:.5px'>DMG-005</span>&nbsp;&nbsp;<span style='font-size:14px;font-weight:600;color:#323130'>Unity Catalog</span><span style='font-size:12px;color:#605e5c;margin-left:8px'>Azure Databricks workspaces for unified analytics governance.</span></div>"
