            "content": {
              "version": "KqlItem/1.0",
              "query": "resources\n| where type == 'microsoft.databricks/workspaces'\n| extend unityCatalog = properties.parameters.enableNoPublicIp\n| project name, location, subscriptionId, properties",
              "size": 3,
              "title": "Databricks Workspaces (Unity Catalog)",
              "queryType": 1,
              "resourceType": "microsoft.resourcegraph/resources",
              "crossComponentResources": [
                "{Subscription}"
              ],
              "visualization": "table",
              "gridSettings": {
                "formatters": [
                  {
                    "columnMatch": "name",
                    "formatter": 13,
                    "formatOptions": {
                      "linkTarget": "Resource",
                      "showIcon": true
                    }
                  }
                ]
              },
              "noDataMessage": "No resources found in the selected subscription(s).",
              "noDataMessageStyle": 4
            },
            "name": "dmg005-query"
          },
          {
            "type": 1,
            "content": {
              "json": "<div style='margin:16px 0 4px 0;border-bottom:1px solid #edebe9;padding-bottom:4px'><span style='font-size:11px;font-weight:600;color:#0078d4;text-transform:uppercase;letter-spacing:.5px'>DMG-006</span>&nbsp;&nbsp;<span style='font-size:14px;font-weight:600;color:#323130'>ADF ETL Coverage</span><span style='font-size:12px;color:#605e5c;margin-left:8px'>Azure Data Factory &#x2014; Data pipelines with Git integration.</span></div>"
            },
            "name": "dmg006-header"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "resources\n| where type == 'microsoft.datafactory/factories'\n| extend gitConfigured = isnotnull(properties.repoConfiguration.repositoryName),\n         globalParams = array_length(bag_keys(properties.globalParameters))\n| project name, location, subscriptionId, gitConfigured, globalParams",
              "size": 3,
              "title": "Data Factories",
              "queryType": 1,
              "resourceType": "microsoft.resourcegraph/resources",
              "crossComponentResources": [
                "{Subscription}"
