            "name": "dmg006-query"
          },
          {
            "type": 1,
            "content": {
              "json": "<div style='margin:16px 0 4px 0;border-bottom:1px solid #edebe9;padding-bottom:4px'><span style='font-size:11px;font-weight:600;color:#0078d4;text-transform:uppercase;letter-spacing:.5px'>DMG-007</span>&nbsp;&nbsp;<span style='font-size:14px;font-weight:600;color:#323130'>Lakehouse Presence</span><span style='font-size:12px;color:#605e5c;margin-left:8px'>ADLS Gen2, Databricks, or Microsoft Fabric for enterprise data lake.</span></div>"
            },
            "name": "dmg007-header"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "resources\n| where type in (\n    'microsoft.storage/storageaccounts',\n    'microsoft.databricks/workspaces',\n    'microsoft.fabric/capacities'\n  )\n| extend layer = case(\n    type == 'microsoft.storage/storageaccounts' and properties.isHnsEnabled == true, 'ADLS Gen2',\n    type == 'microsoft.databricks/workspaces', 'Databricks',\n    type == 'microsoft.fabric/capacities', 'Microsoft Fabric',\n    'Other'\n  )\n| where layer != 'Other'\n| project name, layer, location, subscriptionId",
              "size": 3,
              "title": "Lakehouse Presence",
              "queryType": 1,
              "resourceType": "microsoft.resourcegraph/resources",
              "crossComponentResources": [
                "{Subscription}"
              ],
              "visualization": "table",
              "noDataMessage": "No resources found in the selected subscription(s).",
              "noDataMessageStyle": 4
            },
            "name": "dmg007-query"
          },
          {
            "type": 1,
            "content": {
              "json": "<div style='margin:16px 0 4px 0;border-bottom:1px solid #edebe9;padding-bottom:4px'><span style='font-size:11px;font-weight:600;color:#0078d4;text-transform:uppercase;letter-spacing:.5px'>DMG-008</span>&nbsp;&nbsp;<span style='font-size:14px;font-weight:600;color:#323130'>Retention &amp; Lifecycle Policies</span><span style='font-size:12px;color:#605e5c;margin-left:8px'>ADLS Gen2 lifecycle management policies.</span></div>"
            },
            "name": "dmg008-header"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "resources\n| where type == 'microsoft.storage/storageaccounts'\n| where kind == 'StorageV2' and properties.isHnsEnabled == true\n| extend lifecyclePolicy = isnotnull(properties.managementPolicies)\n| project name, location, subscriptionId, lifecyclePolicy",
              "size": 3,
